188→export async function maybeUpgradeMergedEntityName(
189→  surreal: Surreal,
190→  kind: PersistableExtractableEntityKind,
191→  incomingText: string,
192→  candidate: CandidateEntityRow,
193→  now: Date,
194→): Promise<string> {
195→  if (!isRicherEntityName(incomingText, candidate.text)) {
196→    return candidate.text;
197→  }
198→
199→  if (kind === "project" || kind === "feature") {
200→    await surreal.update(candidate.id as RecordId<"project" | "feature", string>).merge({
201→      name: incomingText,
202→      updated_at: now,
203→    });
204→    return incomingText;
205→  }
206→
207→  if (kind === "task") {
208→    await surreal.update(candidate.id as RecordId<"task", string>).merge({
209→      title: incomingText,
210→      updated_at: now,
