  1→import { RecordId } from "surrealdb";
  2→import type { ExtractedEntity, ExtractedRelationship, OnboardingAction, OnboardingSeedItem } from "../../shared/contracts";
  3→import { buildExtractionComponentBlock } from "../extraction/components";
  4→import { loadAssistantConversationContext, loadConversationGraphContext, loadExtractionConversationContext } from "../extraction/context-loaders";
  5→import { loadBranchChain, loadMessagesWithInheritance } from "./branch-chain";
  6→import { ingestAttachment } from "../extraction/document-ingestion";
  7→import { persistEmbeddings } from "../extraction/embedding-writeback";
  8→import { extractStructuredGraph } from "../extraction/extract-graph";
  9→import { appendExtractedTools, persistExtractionOutput } from "../extraction/persist-extraction";
 10→import type { ConversationRow, GraphEntityRecord, IncomingAttachment, SourceRecord, WorkspaceRow } from "../extraction/types";
 11→import { elapsedMs, logError, logInfo, userFacingError } from "../http/observability";
 12→import { transitionOnboardingState } from "../onboarding/onboarding-state";
 13→import { generateOnboardingAssistantReply } from "../onboarding/onboarding-reply";
 14→import type { ServerDependencies } from "../runtime/types";
 15→import { runOrchestrator } from "./handler";
 16→import { getWorkspaceOwnerRecord } from "../graph/queries";
 17→import { refreshConversationTouchedBy, maybeUpgradeConversationTitle } from "../workspace/conversation-sidebar";
 18→import { loadWorkspaceProjects } from "../workspace/workspace-scope";
 19→
 20→export async function processChatMessage(input: {
 21→  deps: ServerDependencies;
 22→  conversationId: string;
 23→  messageId: string;
 24→  workspaceRecord: RecordId<"workspace", string>;
 25→  userMessageRecord: RecordId<"message", string>;
 26→  userText: string;
 27→  attachment?: IncomingAttachment;
 28→  onboardingAction?: OnboardingAction;
 29→}): Promise<void> {
 30→  const startedAt = performance.now();
 31→  logInfo("chat.message.process.execution.started", "Chat message processing execution started", {
 32→    conversationId: input.conversationId,
 33→    messageId: input.messageId,
 34→    workspaceId: input.workspaceRecord.id as string,
 35→    hasAttachment: input.attachment !== undefined,
 36→  });
 37→
 38→  try {
 39→    const now = new Date();
 40→    const conversationRecord = new RecordId("conversation", input.conversationId);
 41→    const workspace = await input.deps.surreal.select<WorkspaceRow>(input.workspaceRecord);
 42→    if (!workspace) {
 43→      throw new Error("workspace not found");
 44→    }
 45→
 46→    const conversation = await input.deps.surreal.select<ConversationRow>(conversationRecord);
 47→    if (!conversation) {
 48→      throw new Error("conversation not found");
 49→    }
 50→
 51→    // Check if this conversation is a branch and load inherited context
 52→    const branchChain = await loadBranchChain(input.deps.surreal, input.conversationId);
 53→    const isBranch = branchChain.length > 0;
 54→
 55→    let inheritedEntityIds: RecordId[] | undefined;
 56→    let assistantContextRows: Array<{ id: RecordId<"message", string>; role: "user" | "assistant"; text: string; createdAt: Date | string }>;
 57→
 58→    if (isBranch) {
 59→      // For branches, load full message history including inherited messages
 60→      const allMessages = await loadMessagesWithInheritance(input.deps.surreal, input.conversationId, 30);
 61→      assistantContextRows = allMessages
 62→        .map((m) => ({
 63→          id: new RecordId("message", m.id),
 64→          role: m.role,
 65→          text: m.text,
 66→          createdAt: m.createdAt,
 67→        }))
 68→        .slice(-10);
 69→
 70→      // Derive inherited entity IDs from extraction_relations on inherited messages
 71→      const inheritedMsgIds = allMessages
 72→        .filter((m) => m.inherited)
 73→        .map((m) => new RecordId("message", m.id));
 74→
 75→      if (inheritedMsgIds.length > 0) {
 76→        const [entityRows] = await input.deps.surreal
 77→          .query<[Array<{ out: RecordId }>]>(
 78→            "SELECT DISTINCT out FROM extraction_relation WHERE `in` IN $msgIds LIMIT 30;",
 79→            { msgIds: inheritedMsgIds },
 80→          )
 81→          .collect<[Array<{ out: RecordId }>]>();
 82→        inheritedEntityIds = entityRows.map((r) => r.out);
 83→      }
 84→    } else {
 85→      assistantContextRows = await loadAssistantConversationContext(input.deps.surreal, input.conversationId);
 86→    }
 87→
 88→    const extractionConversationContext = await loadExtractionConversationContext({
 89→      surreal: input.deps.surreal,
 90→      conversationId: input.conversationId,
 91→      currentMessageRecord: input.userMessageRecord,
 92→    });
 93→    const extractionGraphContext = await loadConversationGraphContext(
 94→      input.deps.surreal,
 95→      input.conversationId,
 96→      60,
 97→      inheritedEntityIds && inheritedEntityIds.length > 0 ? { inheritedEntityIds } : undefined,
 98→    );
 99→    const workspaceProjects = await loadWorkspaceProjects(input.deps.surreal, input.workspaceRecord);
100→    const workspaceProjectNames = workspaceProjects.map((project) => project.name);
101→    const persistedEntities: ExtractedEntity[] = [];
102→    const persistedRelationships: ExtractedRelationship[] = [];
103→    const seedItems: OnboardingSeedItem[] = [];
104→    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
105→    const extractedTools: string[] = [];
106→    const unresolvedAssigneeNames = new Set<string>();
107→
108→    if (input.attachment) {
109→      const ingestion = await ingestAttachment({
110→        surreal: input.deps.surreal,
111→        extractionModel: input.deps.extractionModel,
112→        embeddingModel: input.deps.embeddingModel,
113→        embeddingDimension: input.deps.config.embeddingDimension,
114→        extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
115→        extractionModelId: input.deps.config.extractionModelId,
116→        workspaceRecord: input.workspaceRecord,
117→        conversationRecord,
118→        userMessageRecord: input.userMessageRecord,
119→        attachment: input.attachment,
120→        workspaceName: workspace.name,
121→        projectNames: workspaceProjectNames,
122→        now,
123→        onChunkResult: (chunkResult) => {
124→          if (chunkResult.entities.length > 0 || chunkResult.relationships.length > 0) {
125→            input.deps.sse.emitEvent(input.messageId, {
126→              type: "extraction",
127→              messageId: input.messageId,
128→              entities: chunkResult.entities,
129→              relationships: chunkResult.relationships,
130→            });
131→          }
132→          if (chunkResult.seeds.length > 0) {
133→            input.deps.sse.emitEvent(input.messageId, {
134→              type: "onboarding_seed",
135→              messageId: input.messageId,
136→              seeds: chunkResult.seeds,
137→            });
138→          }
139→        },
140→      });
141→
142→      persistedEntities.push(...ingestion.entities);
143→      persistedRelationships.push(...ingestion.relationships);
144→      seedItems.push(...ingestion.seeds);
145→      embeddingTargets.push(...ingestion.embeddingTargets);
146→      extractedTools.push(...ingestion.tools);
147→      for (const unresolvedName of ingestion.unresolvedAssigneeNames) {
148→        unresolvedAssigneeNames.add(unresolvedName);
149→      }
150→    }
151→
152→    const textExtraction = await extractStructuredGraph({
153→      extractionModel: input.deps.extractionModel,
154→      conversationHistory: extractionConversationContext.conversationHistory,
155→      currentMessage: extractionConversationContext.currentMessage,
156→      graphContext: extractionGraphContext,
157→      sourceText: input.userText,
158→      onboarding: !workspace.onboarding_complete,
159→      workspaceName: workspace.name,
160→      projectNames: workspaceProjectNames,
161→    });
162→
163→    const textPersistence = await persistExtractionOutput({
164→      surreal: input.deps.surreal,
165→      embeddingModel: input.deps.embeddingModel,
166→      embeddingDimension: input.deps.config.embeddingDimension,
167→      extractionModelId: input.deps.config.extractionModelId,
168→      extractionStoreThreshold: input.deps.config.extractionStoreThreshold,
169→      workspaceRecord: input.workspaceRecord,
170→      sourceRecord: input.userMessageRecord as SourceRecord,
171→      sourceKind: "message",
172→      sourceLabel: input.userText.slice(0, 140),
173→      promptText: input.userText,
174→      output: textExtraction,
175→      sourceMessageRecord: input.userMessageRecord,
176→      extractionHistoryMessageIds: extractionConversationContext.conversationHistory.map((row) => row.id.id as string),
177→      now,
178→    });
179→
180→    persistedEntities.push(...textPersistence.entities);
181→    persistedRelationships.push(...textPersistence.relationships);
182→    seedItems.push(...textPersistence.seeds);
183→    embeddingTargets.push(...textPersistence.embeddingTargets);
184→    extractedTools.push(...textPersistence.tools);
185→    for (const unresolvedName of textPersistence.unresolvedAssigneeNames) {
186→      unresolvedAssigneeNames.add(unresolvedName);
187→    }
188→
189→    const dedupedTools = [...new Set(extractedTools.map((tool) => tool.trim()).filter((tool) => tool.length > 0))];
190→    await appendExtractedTools(input.deps.surreal, input.workspaceRecord, extractedTools, now);
191→
192→    await refreshConversationTouchedBy(input.deps.surreal, conversationRecord);
193→    await maybeUpgradeConversationTitle(input.deps.surreal, conversationRecord);
194→
195→    const onboardingBefore = workspace.onboarding_complete
196→      ? "complete"
197→      : workspace.onboarding_summary_pending
198→        ? "summary_pending"
199→        : "active";
200→
201→    const onboardingAfter = await transitionOnboardingState({
202→      surreal: input.deps.surreal,
203→      workspaceRecord: input.workspaceRecord,
204→      workspace,
205→      onboardingAction: input.onboardingAction,
206→      now,
207→    });
208→
209→    let assistantText = "";
210→    let assistantSuggestions: string[] = [];
211→    const unresolvedAssigneeSuggestions = [...unresolvedAssigneeNames].map(
212→      (name) => `You mentioned ${name} - want to add them to workspace people?`,
213→    );
214→
215→    if (onboardingAfter === "complete") {
216→      const workspaceOwnerRecord = await getWorkspaceOwnerRecord({
217→        surreal: input.deps.surreal,
218→        workspaceRecord: input.workspaceRecord,
219→      });
220→
221→      const graphAwareResponse = await runOrchestrator({
222→        surreal: input.deps.surreal,
223→        model: input.deps.assistantModel,
224→        pmModel: input.deps.pmModel,
225→        embeddingModel: input.deps.embeddingModel,
226→        embeddingDimension: input.deps.config.embeddingDimension,
227→        extractionModelId: input.deps.config.extractionModelId,
228→        conversationRecord,
229→        workspaceRecord: input.workspaceRecord,
230→        currentMessageRecord: input.userMessageRecord,
231→        latestUserText: input.userText,
232→        ...(workspaceOwnerRecord ? { workspaceOwnerRecord } : {}),
233→        ...(inheritedEntityIds && inheritedEntityIds.length > 0 ? { inheritedEntityIds } : {}),
234→        messages: assistantContextRows.map((row) => ({
235→          role: row.role,
236→          text: row.text,
237→        })),
238→        onToken: async (token) => {
239→          input.deps.sse.emitEvent(input.messageId, {
240→            type: "token",
241→            messageId: input.messageId,
242→            token,
243→          });
244→        },
245→      });
246→
247→      assistantText = graphAwareResponse.text.trim();
248→    } else {
249→      const assistantReply = await generateOnboardingAssistantReply({
250→        assistantModel: input.deps.assistantModel,
251→        surreal: input.deps.surreal,
252→        onboardingState: onboardingAfter,
253→        contextRows: assistantContextRows,
254→        latestUserText: input.userText,
255→        workspaceRecord: input.workspaceRecord,
256→        latestEntities: persistedEntities.map((entity) => ({
257→          kind: entity.kind,
258→          text: entity.text,
259→          confidence: entity.confidence,
260→        })),
261→        latestTools: dedupedTools,
262→      });
263→
264→      assistantText = assistantReply.message.trim();
265→      assistantSuggestions = assistantReply.suggestions;
266→
267→      for (const token of assistantText.split(" ")) {
268→        input.deps.sse.emitEvent(input.messageId, {
269→          type: "token",
270→          messageId: input.messageId,
271→          token: `${token} `,
272→        });
273→        await new Promise((resolve) => setTimeout(resolve, 25));
274→      }
275→    }
276→
277→    assistantSuggestions = sanitizeAssistantSuggestions(
278→      [...assistantSuggestions, ...unresolvedAssigneeSuggestions],
279→      3,
280→    );
281→
282→    const summaryBlock = buildExtractionComponentBlock(
283→      persistedEntities,
284→      persistedRelationships,
285→      input.deps.config.extractionDisplayThreshold,
286→    );
287→
288→    if (summaryBlock) {
289→      if (onboardingAfter === "complete") {
290→        const streamChunk = assistantText.length > 0 ? `\n\n${summaryBlock}` : summaryBlock;
291→        for (const token of streamChunk.split(" ")) {
292→          input.deps.sse.emitEvent(input.messageId, {
293→            type: "token",
294→            messageId: input.messageId,
295→            token: `${token} `,
296→          });
297→        }
298→      }
299→
300→      assistantText = assistantText.length > 0 ? `${assistantText}\n\n${summaryBlock}` : summaryBlock;
301→    }
302→
303→    if (assistantText.trim().length === 0) {
304→      assistantText = "I could not generate a response for that request.";
305→    }
306→
307→    const assistantMessageRecord = new RecordId("message", input.messageId);
308→    await input.deps.surreal.create(assistantMessageRecord).content({
309→      conversation: conversationRecord,
310→      role: "assistant",
311→      text: assistantText,
312→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
313→      createdAt: now,
314→    });
315→
316→    await input.deps.surreal.update(conversationRecord).merge({
317→      updatedAt: now,
318→    });
319→
320→    void persistEmbeddings({
321→      surreal: input.deps.surreal,
322→      embeddingModel: input.deps.embeddingModel,
323→      embeddingDimension: input.deps.config.embeddingDimension,
324→      assistantMessageRecord,
325→      assistantText,
326→      entities: embeddingTargets,
327→    }).catch(() => undefined);
328→
329→    input.deps.sse.emitEvent(input.messageId, {
330→      type: "extraction",
331→      messageId: input.messageId,
332→      entities: persistedEntities,
333→      relationships: persistedRelationships,
334→    });
335→
336→    if (seedItems.length > 0) {
337→      input.deps.sse.emitEvent(input.messageId, {
338→        type: "onboarding_seed",
339→        messageId: input.messageId,
340→        seeds: seedItems,
341→      });
342→    }
343→
344→    if (onboardingBefore !== onboardingAfter) {
345→      input.deps.sse.emitEvent(input.messageId, {
346→        type: "onboarding_state",
347→        messageId: input.messageId,
348→        onboardingState: onboardingAfter,
349→      });
350→    }
351→
352→    input.deps.sse.emitEvent(input.messageId, {
353→      type: "assistant_message",
354→      messageId: input.messageId,
355→      text: assistantText,
356→      ...(assistantSuggestions.length > 0 ? { suggestions: assistantSuggestions } : {}),
357→    });
358→
359→    input.deps.sse.emitEvent(input.messageId, {
360→      type: "done",
361→      messageId: input.messageId,
362→    });
363→
364→    logInfo("chat.message.process.execution.completed", "Chat message processing execution completed", {
365→      conversationId: input.conversationId,
366→      messageId: input.messageId,
367→      workspaceId: input.workspaceRecord.id as string,
368→      entityCount: persistedEntities.length,
369→      relationshipCount: persistedRelationships.length,
370→      seedCount: seedItems.length,
371→      durationMs: elapsedMs(startedAt),
372→    });
373→  } catch (error) {
374→    logError("chat.message.process.execution.failed", "Chat message processing execution failed", error, {
375→      conversationId: input.conversationId,
376→      messageId: input.messageId,
377→      workspaceId: input.workspaceRecord.id as string,
378→      durationMs: elapsedMs(startedAt),
