231→export async function createProvenanceEdge(input: {
232→  surreal: Surreal;
233→  sourceRecord: SourceRecord;
234→  targetRecord: GraphEntityRecord;
235→  confidence: number;
236→  model: string;
237→  now: Date;
238→  fromText: string;
239→  evidence: string;
240→  evidenceSourceRecord?: RecordId<"message", string>;
241→  resolvedFromRecord?: RecordId<"message", string>;
242→}): Promise<void> {
243→  await input.surreal.relate(input.sourceRecord, new RecordId("extraction_relation", randomUUID()), input.targetRecord, {
244→    confidence: input.confidence,
245→    extracted_at: input.now,
246→    created_at: input.now,
247→    model: input.model,
248→    from_text: input.fromText,
249→    evidence: input.evidence,
250→    ...(input.evidenceSourceRecord ? { evidence_source: input.evidenceSourceRecord } : {}),
251→    ...(input.resolvedFromRecord ? { resolved_from: input.resolvedFromRecord } : {}),
252→  }).output("after");
253→}
