326→export async function loadWorkspaceKindCandidates(
327→  surreal: Surreal,
328→  workspaceRecord: RecordId<"workspace", string>,
329→  kind: ExtractableEntityKind,
330→): Promise<CandidateEntityRow[]> {
331→  if (kind === "project") {
332→    const [rows] = await surreal
333→      .query<[CandidateEntityRow[]]>(
334→        "SELECT id, name AS text, embedding FROM project WHERE id IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace);",
335→        { workspace: workspaceRecord },
336→      )
337→      .collect<[CandidateEntityRow[]]>();
338→    return rows;
339→  }
340→
341→  if (kind === "person") {
342→    const [rows] = await surreal
343→      .query<[CandidateEntityRow[]]>(
344→        "SELECT id, name AS text, embedding FROM person WHERE id IN (SELECT VALUE `in` FROM member_of WHERE out = $workspace);",
345→        { workspace: workspaceRecord },
346→      )
347→      .collect<[CandidateEntityRow[]]>();
348→    return rows;
349→  }
350→
351→  if (kind === "feature") {
352→    const [rows] = await surreal
353→      .query<[CandidateEntityRow[]]>(
354→        [
355→          "SELECT id, name AS text, embedding",
356→          "FROM feature",
357→          "WHERE id IN (",
358→          "  SELECT VALUE out",
359→          "  FROM has_feature",
360→          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
361→          ");",
362→        ].join(" "),
363→        { workspace: workspaceRecord },
364→      )
365→      .collect<[CandidateEntityRow[]]>();
366→    return rows;
367→  }
368→
369→  if (kind === "task") {
370→    const [rows] = await surreal
371→      .query<[CandidateEntityRow[]]>(
372→        [
373→          "SELECT id, title AS text, embedding",
374→          "FROM task",
375→          "WHERE id IN (",
376→          "  SELECT VALUE `in`",
377→          "  FROM belongs_to",
378→          "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
379→          ")",
380→          "OR source_message IN (",
381→          "  SELECT VALUE id",
382→          "  FROM message",
383→          "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
384→          ");",
385→        ].join(" "),
386→        { workspace: workspaceRecord },
387→      )
388→      .collect<[CandidateEntityRow[]]>();
389→    return uniqueCandidateRows(rows);
390→  }
391→
392→  if (kind === "decision") {
393→    const [rows] = await surreal
394→      .query<[CandidateEntityRow[]]>(
395→        [
396→          "SELECT id, summary AS text, embedding",
397→          "FROM decision",
398→          "WHERE id IN (",
399→          "  SELECT VALUE `in`",
400→          "  FROM belongs_to",
401→          "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
402→          ")",
403→          "OR source_message IN (",
404→          "  SELECT VALUE id",
405→          "  FROM message",
406→          "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
407→          ");",
408→        ].join(" "),
409→        { workspace: workspaceRecord },
410→      )
411→      .collect<[CandidateEntityRow[]]>();
412→    return uniqueCandidateRows(rows);
413→  }
414→
415→  const [rows] = await surreal
416→    .query<[CandidateEntityRow[]]>(
417→      [
418→        "SELECT id, text AS text, embedding",
419→        "FROM question",
420→        "WHERE id IN (",
421→        "  SELECT VALUE `in`",
422→        "  FROM belongs_to",
423→        "  WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
424→        ")",
425→        "OR source_message IN (",
426→        "  SELECT VALUE id",
427→        "  FROM message",
428→        "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
429→        ");",
430→      ].join(" "),
431→      { workspace: workspaceRecord },
432→    )
433→    .collect<[CandidateEntityRow[]]>();
434→  return uniqueCandidateRows(rows);
435→}
