445→export async function appendWorkspaceTools(
446→  surreal: Surreal,
447→  workspaceRecord: RecordId<"workspace", string>,
448→  toolsToAdd: string[],
449→  now: Date,
450→): Promise<void> {
451→  const [rows] = await surreal
452→    .query<[Array<{ tools?: string[] }>]>("SELECT tools FROM $workspace LIMIT 1;", {
453→      workspace: workspaceRecord,
454→    })
455→    .collect<[Array<{ tools?: string[] }>]>();
456→
457→  const existingTools = rows[0]?.tools ?? [];
458→  const merged = [...new Set([...existingTools, ...toolsToAdd])];
459→  await surreal.update(workspaceRecord).merge({
460→    tools: merged,
461→    updated_at: now,
462→  });
463→}
