 1→import { tool } from "ai";
 2→import { z } from "zod";
 3→import { confirmDecisionRecord, getDecisionRecordForWorkspace, getWorkspaceOwnerRecord } from "../../graph/queries";
 4→import { requireToolContext, toDecisionRecordId } from "./helpers";
 5→import type { ChatToolDeps } from "./types";
 6→
 7→const CONFIRMABLE_STATUSES = new Set(["provisional", "inferred"]);
 8→
 9→export function createConfirmDecisionTool(deps: ChatToolDeps) {
10→  return tool({
11→    description:
12→      "Confirm a provisional or inferred decision. ONLY use this when the user explicitly approves a decision in conversation. Never call this without clear user authorization.",
13→    inputSchema: z.object({
14→      decision_id: z.string().min(1).describe("Decision record ID to confirm"),
15→      notes: z.string().optional().describe("Additional user context"),
16→    }),
17→    execute: async (input, options) => {
18→      const context = requireToolContext(options);
19→
20→      if (context.actor !== "chat_agent" && context.actor !== "orchestrator") {
21→        throw new Error("confirm_decision is only available for chat_agent or orchestrator context");
22→      }
23→
24→      const decisionRecord = toDecisionRecordId(input.decision_id);
25→      const decision = await getDecisionRecordForWorkspace({
26→        surreal: deps.surreal,
27→        workspaceRecord: context.workspaceRecord,
28→        decisionInput: `decision:${decisionRecord.id as string}`,
29→      });
30→
31→      if (!CONFIRMABLE_STATUSES.has(decision.status)) {
32→        throw new Error(`decision is not confirmable from status '${decision.status}'`);
33→      }
34→
35→      const ownerRecord = context.workspaceOwnerRecord
36→        ? context.workspaceOwnerRecord
37→        : await getWorkspaceOwnerRecord({
38→            surreal: deps.surreal,
39→            workspaceRecord: context.workspaceRecord,
40→          });
41→
42→      const confirmedAt = new Date();
43→      await confirmDecisionRecord({
44→        surreal: deps.surreal,
45→        decisionRecord: decision.id,
46→        confirmedAt,
47→        ...(ownerRecord ? { confirmedBy: ownerRecord } : {}),
48→        ...(input.notes ? { notes: input.notes } : {}),
49→      });
50→
51→      return {
52→        decision_id: `decision:${decision.id.id as string}`,
53→        status: "confirmed",
54→        name: decision.summary,
55→      };
56→    },
57→  });
58→}
