  1→import { tool } from "ai";
  2→import { z } from "zod";
  3→import { createEmbeddingVector } from "../../graph/embeddings";
  4→import {
  5→  createDecisionRecord,
  6→  createExtractionProvenanceEdge,
  7→  getDecisionPrimarySourceMessage,
  8→  listDecisionConstraintCandidates,
  9→  parseRecordIdString,
 10→  resolveWorkspaceFeatureRecord,
 11→  resolveWorkspaceProjectRecord,
 12→  type GraphEntityRecord,
 13→} from "../../graph/queries";
 14→import { requireToolContext } from "./helpers";
 15→import type { ChatToolDeps } from "./types";
 16→
 17→const resolveDecisionInputSchema = z.object({
 18→  question: z.string().min(1).describe("The decision question"),
 19→  options: z.array(z.string().min(1)).optional().describe("Known options being considered"),
 20→  context: z
 21→    .object({
 22→      project: z.string().optional(),
 23→      feature: z.string().optional(),
 24→    })
 25→    .optional()
 26→    .describe("Optional project/feature scope for searching decisions"),
 27→});
 28→
 29→export function createResolveDecisionTool(deps: ChatToolDeps) {
 30→  return tool({
 31→    description:
 32→      "Infer an answer to a decision question from graph context. Returns resolved/inferred/unresolved with rationale and sources.",
 33→    inputSchema: resolveDecisionInputSchema,
 34→    execute: async (input, options) => {
 35→      const context = requireToolContext(options);
 36→      const queryEmbedding = await createEmbeddingVector(deps.embeddingModel, input.question, deps.embeddingDimension);
 37→      if (!queryEmbedding) {
 38→        throw new Error("failed to create query embedding for resolve_decision");
 39→      }
 40→
 41→      const projectRecord = input.context?.project
 42→        ? await resolveWorkspaceProjectRecord({
 43→            surreal: deps.surreal,
 44→            workspaceRecord: context.workspaceRecord,
 45→            projectInput: input.context.project,
 46→          })
 47→        : undefined;
 48→
 49→      const featureRecord = input.context?.feature
 50→        ? await resolveWorkspaceFeatureRecord({
 51→            surreal: deps.surreal,
 52→            workspaceRecord: context.workspaceRecord,
 53→            featureInput: input.context.feature,
 54→          })
 55→        : undefined;
 56→
 57→      const candidates = await listDecisionConstraintCandidates({
 58→        surreal: deps.surreal,
 59→        workspaceRecord: context.workspaceRecord,
 60→        queryEmbedding,
 61→        ...(projectRecord ? { projectRecord } : {}),
 62→        limit: 10,
 63→      });
 64→
 65→      const decisionCandidates = candidates.filter((candidate) => candidate.kind === "decision");
 66→      const topDecision = decisionCandidates[0];
 67→
 68→      if (topDecision && topDecision.score >= 0.92) {
 69→        const existingDecision = parseRecordIdString(topDecision.id, ["decision"], "decision");
 70→        const resolvedFrom = await getDecisionPrimarySourceMessage({
 71→          surreal: deps.surreal,
 72→          workspaceRecord: context.workspaceRecord,
 73→          decisionRecord: existingDecision,
 74→        });
 75→
 76→        await createExtractionProvenanceEdge({
 77→          surreal: deps.surreal,
 78→          sourceRecord: context.currentMessageRecord,
 79→          targetRecord: existingDecision,
 80→          now: new Date(),
 81→          confidence: Math.max(topDecision.score, 0.6),
 82→          model: deps.extractionModelId,
 83→          fromText: input.question,
 84→          evidence: context.latestUserText,
 85→          evidenceSourceRecord: context.currentMessageRecord,
 86→          ...(resolvedFrom ? { resolvedFromRecord: resolvedFrom } : {}),
 87→        });
 88→
 89→        return {
 90→          status: "resolved",
 91→          decision: {
 92→            id: `decision:${topDecision.id}`,
 93→            name: topDecision.name,
 94→          },
 95→          confidence: Number(topDecision.score.toFixed(4)),
 96→          sources: [
 97→            {
 98→              id: `decision:${topDecision.id}`,
 99→              name: topDecision.name,
100→              score: Number(topDecision.score.toFixed(4)),
101→            },
102→          ],
103→        };
104→      }
105→
106→      if (topDecision && topDecision.score >= 0.78) {
107→        const now = new Date();
108→        const sources = candidates.slice(0, 5);
109→        const basedOn = sources
110→          .map((source) => {
111→            try {
112→              return parseRecordIdString(source.id, [source.kind as "project" | "feature" | "task" | "decision" | "question"], source.kind as any);
113→            } catch {
114→              return undefined;
115→            }
116→          })
117→          .filter((value): value is GraphEntityRecord => value !== undefined);
118→
119→        const decisionRecord = await createDecisionRecord({
120→          surreal: deps.surreal,
121→          summary: input.question,
122→          status: "inferred",
123→          now,
124→          sourceMessageRecord: context.currentMessageRecord,
125→          rationale: `Inferred from existing graph context with ${sources.length} related entities.`,
126→          ...(input.options && input.options.length > 0 ? { optionsConsidered: input.options } : {}),
127→          ...(basedOn.length > 0 ? { basedOn } : {}),
128→          inferredBy: "chat_agent",
129→          decidedByName: "chat_agent",
130→          ...(projectRecord ? { projectRecord } : {}),
131→          ...(featureRecord ? { featureRecord } : {}),
132→        });
133→
134→        await createExtractionProvenanceEdge({
135→          surreal: deps.surreal,
136→          sourceRecord: context.currentMessageRecord,
137→          targetRecord: decisionRecord,
138→          now,
139→          confidence: Math.max(topDecision.score, 0.6),
140→          model: deps.extractionModelId,
141→          fromText: input.question,
142→          evidence: context.latestUserText,
143→          evidenceSourceRecord: context.currentMessageRecord,
144→        });
145→
146→        return {
147→          status: "inferred",
148→          decision: {
149→            id: `decision:${decisionRecord.id as string}`,
150→            name: input.question,
151→          },
152→          confidence: Number(topDecision.score.toFixed(4)),
153→          rationale: `Top matching decision: ${topDecision.name}. Related context was strong enough to infer a recommendation.`,
154→          sources: sources.map((source) => ({
155→            id: `${source.kind}:${source.id}`,
156→            name: source.name,
157→            score: Number(source.score.toFixed(4)),
158→          })),
159→        };
160→      }
161→
162→      return {
163→        status: "unresolved",
164→        relatedContext: candidates.slice(0, 6).map((source) => ({
165→          id: `${source.kind}:${source.id}`,
166→          kind: source.kind,
167→          name: source.name,
168→          score: Number(source.score.toFixed(4)),
169→        })),
170→        suggestProvisional: true,
171→      };
172→    },
173→  });
174→}
