  1→import { generateObject } from "ai";
  2→import {
  3→  extractionResultSchema,
  4→  type ExtractionPromptOutput,
  5→} from "./schema";
  6→import { buildExtractionSystemPrompt } from "./prompt";
  7→import type { ExtractionGraphContextRow, MessageContextRow } from "./types";
  8→import { elapsedMs, logError, logInfo } from "../http/observability";
  9→
 10→export async function extractStructuredGraph(input: {
 11→  extractionModel: any;
 12→  conversationHistory: MessageContextRow[];
 13→  currentMessage?: MessageContextRow;
 14→  graphContext: ExtractionGraphContextRow[];
 15→  sourceText: string;
 16→  onboarding: boolean;
 17→  heading?: string;
 18→  workspaceName?: string;
 19→  projectNames?: string[];
 20→}): Promise<ExtractionPromptOutput> {
 21→  const startedAt = performance.now();
 22→  logInfo("extraction.generate.started", "Structured extraction started", {
 23→    onboarding: input.onboarding,
 24→    hasHeading: input.heading !== undefined,
 25→    contextMessageCount: input.conversationHistory.length,
 26→    hasCurrentMessage: input.currentMessage !== undefined,
 27→    graphContextCount: input.graphContext.length,
 28→    sourceLength: input.sourceText.length,
 29→  });
 30→
 31→  try {
 32→    const extractionOutput = await generateObject({
 33→      model: input.extractionModel,
 34→      schema: extractionResultSchema,
 35→      temperature: 0.1,
 36→      system: buildExtractionSystemPrompt({ onboarding: input.onboarding }),
 37→      prompt: [
 38→        "Conversation history (reference resolution only):",
 39→        formatExtractionConversationHistory(input.conversationHistory),
 40→        "",
 41→        "Current message (extract only from this text when message metadata exists):",
 42→        formatExtractionCurrentMessage(input.currentMessage, input.sourceText),
 43→        "",
 44→        "Resolved-from lineage constraints:",
 45→        formatResolvedFromConstraints(input.currentMessage, input.conversationHistory),
 46→        "",
 47→        "Existing graph context (semantic index of prior extracted entities):",
 48→        formatExtractionGraphContext(input.graphContext),
 49→        "",
 50→        "Workspace scope:",
 51→        formatWorkspaceScope(input.workspaceName, input.projectNames),
 52→        input.heading ? `Section heading: ${input.heading}` : "",
 53→        "",
 54→        "Current source text:",
 55→        input.sourceText,
 56→      ]
 57→        .filter((line) => line.length > 0)
 58→        .join("\n"),
 59→    });
 60→
 61→    const output = extractionOutput.object as ExtractionPromptOutput;
 62→    logInfo("extraction.generate.completed", "Structured extraction completed", {
 63→      onboarding: input.onboarding,
 64→      entityCount: output.entities.length,
 65→      relationshipCount: output.relationships.length,
 66→      toolCount: output.tools.length,
 67→      durationMs: elapsedMs(startedAt),
 68→    });
 69→
 70→    return output;
 71→  } catch (error) {
 72→    logError("extraction.generate.failed", "Structured extraction failed", error, {
 73→      onboarding: input.onboarding,
 74→      durationMs: elapsedMs(startedAt),
 75→    });
 76→    throw error;
 77→  }
 78→}
 79→
 80→function formatExtractionConversationHistory(rows: MessageContextRow[]): string {
 81→  if (rows.length === 0) {
 82→    return "(no prior messages)";
 83→  }
 84→
 85→  return rows.map((row) => `[message:${row.id.id as string}] ${row.role.toUpperCase()}: ${row.text}`).join("\n");
 86→}
 87→
 88→function formatExtractionCurrentMessage(currentMessage: MessageContextRow | undefined, sourceText: string): string {
 89→  if (!currentMessage) {
 90→    return `(no message metadata; source text: ${sourceText})`;
 91→  }
 92→
 93→  return `[message:${currentMessage.id.id as string}] ${currentMessage.role.toUpperCase()}: ${currentMessage.text}`;
 94→}
 95→
 96→function formatExtractionGraphContext(rows: ExtractionGraphContextRow[]): string {
 97→  if (rows.length === 0) {
 98→    return "(no prior extracted entities)";
 99→  }
100→
101→  return rows
102→    .map((row) => {
103→      const table = row.id.tb;
104→      return `[entity:${table}:${row.id.id as string}] ${row.kind}: ${row.text} (confidence ${row.confidence.toFixed(2)}, source message ${row.sourceMessage.id as string})`;
105→    })
106→    .join("\n");
107→}
108→
109→function formatWorkspaceScope(workspaceName?: string, projectNames?: string[]): string {
110→  if (!workspaceName) {
111→    return "(no workspace context)";
112→  }
113→
114→  const lines = [`Workspace: "${workspaceName}"`];
115→  if (projectNames && projectNames.length > 0) {
116→    lines.push(`Existing projects: ${projectNames.map((name) => `"${name}"`).join(", ")}`);
117→  } else {
118→    lines.push("Existing projects: none");
119→  }
120→
121→  return lines.join("\n");
122→}
123→
124→function formatResolvedFromConstraints(
125→  currentMessage: MessageContextRow | undefined,
126→  conversationHistory: MessageContextRow[],
127→): string {
128→  if (!currentMessage) {
129→    return "Current message id unavailable; omit resolvedFromMessageId.";
130→  }
131→
132→  const currentMessageId = currentMessage.id.id as string;
133→  if (conversationHistory.length === 0) {
134→    return [
135→      `Current message id (forbidden for resolvedFromMessageId): ${currentMessageId}`,
136→      "Allowed resolvedFromMessageId values (history only): none",
137→      "Omit resolvedFromMessageId.",
138→    ].join("\n");
139→  }
140→
141→  const historyMessageIds = conversationHistory.map((row) => row.id.id as string);
142→  return [
143→    `Current message id (forbidden for resolvedFromMessageId): ${currentMessageId}`,
144→    `Allowed resolvedFromMessageId values (history only): ${historyMessageIds.join(", ")}`,
145→    "Use one of the allowed ids exactly, or omit resolvedFromMessageId.",
146→  ].join("\n");
147→}
