 81→function parseJsonPayload(raw: string): unknown {
 82→  const trimmed = raw.trim();
 83→  if (trimmed.length === 0) {
 84→    throw new Error("pm agent returned empty text");
 85→  }
 86→
 87→  try {
 88→    return JSON.parse(trimmed);
 89→  } catch (error) {
 90→    throw new Error(`pm agent output is not valid strict JSON: ${error instanceof Error ? error.message : "parse error"}`);
 91→  }
 92→}
 93→
 94→export async function runPmAgent(input: PmAgentInput): Promise<PmAgentResult> {
 95→  const system = await buildPmSystemPrompt({
 96→    surreal: input.surreal,
 97→    workspaceRecord: input.workspaceRecord,
 98→  });
 99→  const intentInstruction = input.intent === "check_status"
100→    ? "Primary action: call get_project_status when a project scope is available."
101→    : input.intent === "plan_work"
102→      ? "Primary action: propose tasks/features with suggest_work_items, deduping each item."
103→      : input.intent === "track_dependencies"
104→        ? "Primary action: identify blockers/dependencies and create observations for high-risk paths."
105→        : "Primary action: organize work into clear, deduplicated next steps.";
106→
107→  const result = await generateText({
108→    model: input.pmModel,
109→    system,
110→    prompt: [
111→      "You are handling a PM request.",
112→      `Intent: ${input.intent}`,
113→      input.project ? `Project hint: ${input.project}` : "Project hint: not provided",
114→      intentInstruction,
115→      "Context:",
116→      input.context,
117→      "",
118→      "Return strict JSON only. Do not include markdown.",
119→      "Schema:",
120→      '{"summary": string, "suggestions": WorkItemSuggestion[], "updated": Array<{"existing_id": string, "title": string, "changes": string}>, "discarded": Array<{"title": string, "reason": string}>, "observations_created": string[]}',
121→    ].join("\n"),
122→    tools: createPmTools({
123→      surreal: input.surreal,
124→      embeddingModel: input.embeddingModel,
125→      embeddingDimension: input.embeddingDimension,
126→      extractionModelId: input.extractionModelId,
127→    }),
128→    experimental_context: {
129→      actor: "pm_agent",
130→      workspaceRecord: input.workspaceRecord,
131→      conversationRecord: input.conversationRecord,
132→      currentMessageRecord: input.currentMessageRecord,
133→      latestUserText: input.latestUserText,
134→      ...(input.workspaceOwnerRecord ? { workspaceOwnerRecord: input.workspaceOwnerRecord } : {}),
135→    },
136→    maxSteps: 5,
137→  });
138→
139→  const parsed = pmAgentResultSchema.safeParse(parseJsonPayload(result.text));
140→  if (!parsed.success) {
141→    throw new Error(`pm agent output failed validation: ${parsed.error.message}`);
142→  }
143→
144→  return parsed.data;
145→}
