 23→export function createWorkItemAcceptHandler(
 24→  deps: ServerDependencies,
 25→): (workspaceId: string, request: Request) => Promise<Response> {
 26→  return (workspaceId: string, request: Request) =>
 27→    handleAcceptWorkItem(deps, workspaceId, request);
 28→}
 29→
 30→async function handleAcceptWorkItem(
 31→  deps: ServerDependencies,
 32→  workspaceId: string,
 33→  request: Request,
 34→): Promise<Response> {
 35→  let body: unknown;
 36→  try {
 37→    body = await request.json();
 38→  } catch {
 39→    return jsonError("invalid JSON body", 400);
 40→  }
 41→
 42→  const parsed = acceptWorkItemSchema.safeParse(body);
 43→  if (!parsed.success) {
 44→    return jsonError(`invalid work item: ${parsed.error.message}`, 400);
 45→  }
 46→
 47→  const item = parsed.data;
 48→
 49→  let workspaceRecord: RecordId<"workspace", string>;
 50→  try {
 51→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 52→  } catch (error) {
 53→    if (error instanceof HttpError) {
 54→      return jsonError(error.message, error.status);
 55→    }
 56→    logError("work-item.accept.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 57→    return jsonError("failed to resolve workspace", 500);
 58→  }
 59→
 60→  try {
 61→    const now = new Date();
 62→    const embedding = await createEmbeddingVector(
 63→      deps.embeddingModel,
 64→      item.title,
 65→      deps.config.embeddingDimension,
 66→    );
 67→
 68→    const entityId = randomUUID();
 69→
 70→    if (item.kind === "task") {
 71→      const taskRecord = new RecordId("task", entityId);
 72→      await deps.surreal.create(taskRecord).content({
 73→        title: item.title,
 74→        status: "open",
 75→        ...(item.category ? { category: item.category } : {}),
 76→        ...(item.priority ? { priority: item.priority } : {}),
 77→        ...(embedding ? { embedding } : {}),
 78→        created_at: now,
 79→        updated_at: now,
 80→      });
 81→
 82→      if (item.project) {
 83→        try {
 84→          const projectRecord = await resolveWorkspaceProjectRecord({
 85→            surreal: deps.surreal,
 86→            workspaceRecord,
 87→            projectInput: item.project,
 88→          });
 89→          await deps.surreal
 90→            .relate(taskRecord, new RecordId("belongs_to", randomUUID()), projectRecord, {
 91→              added_at: now,
 92→            })
 93→            .output("after");
 94→        } catch {
 95→          // project resolution is best-effort; task still created
 96→        }
 97→      }
 98→
 99→      logInfo("work-item.accept.task.created", "Task created from work item suggestion", {
100→        workspaceId,
101→        entityId,
102→        title: item.title,
103→      });
104→
105→      return jsonResponse({ entityId: `task:${entityId}` }, 201);
106→    }
107→
108→    // feature
109→    const featureRecord = new RecordId("feature", entityId);
110→    await deps.surreal.create(featureRecord).content({
111→      name: item.title,
112→      status: "active",
113→      ...(item.category ? { category: item.category } : {}),
114→      ...(embedding ? { embedding } : {}),
115→      created_at: now,
116→      updated_at: now,
117→    });
118→
119→    if (item.project) {
120→      try {
121→        const projectRecord = await resolveWorkspaceProjectRecord({
122→          surreal: deps.surreal,
123→          workspaceRecord,
124→          projectInput: item.project,
125→        });
126→        await ensureProjectFeatureEdge(deps.surreal, projectRecord, featureRecord, now);
127→      } catch {
128→        // project resolution is best-effort; feature still created
129→      }
130→    }
131→
132→    logInfo("work-item.accept.feature.created", "Feature created from work item suggestion", {
133→      workspaceId,
134→      entityId,
135→      title: item.title,
136→    });
137→
138→    return jsonResponse({ entityId: `feature:${entityId}` }, 201);
139→  } catch (error) {
140→    logError("work-item.accept.failed", "Failed to accept work item", error, {
141→      workspaceId,
142→      kind: item.kind,
143→      title: item.title,
144→    });
145→    const message = error instanceof Error ? error.message : "work item accept failed";
146→    return jsonError(message, 500);
147→  }
148→}
