232→export async function isEntityInWorkspace(
233→  surreal: Surreal,
234→  workspaceRecord: RecordId<"workspace", string>,
235→  entityRecord: GraphEntityRecord,
236→): Promise<boolean> {
237→  const table = entityRecord.table.name;
238→
239→  if (table === "workspace") {
240→    return toRecordIdString(entityRecord) === toRecordIdString(workspaceRecord);
241→  }
242→
243→  if (table === "project") {
244→    const [rows] = await surreal
245→      .query<[Array<{ id: RecordId<"has_project", string> }>]>(
246→        "SELECT id FROM has_project WHERE `in` = $workspace AND out = $project LIMIT 1;",
247→        { workspace: workspaceRecord, project: entityRecord },
248→      )
249→      .collect<[Array<{ id: RecordId<"has_project", string> }>]>();
250→
251→    return rows.length > 0;
252→  }
253→
254→  if (table === "person") {
255→    const [rows] = await surreal
256→      .query<[Array<{ id: RecordId<"member_of", string> }>]>(
257→        "SELECT id FROM member_of WHERE `in` = $person AND out = $workspace LIMIT 1;",
258→        { workspace: workspaceRecord, person: entityRecord },
259→      )
260→      .collect<[Array<{ id: RecordId<"member_of", string> }>]>();
261→
262→    return rows.length > 0;
263→  }
264→
265→  if (table === "feature") {
266→    const [rows] = await surreal
267→      .query<[Array<{ id: RecordId<"feature", string> }>]>(
268→        [
269→          "SELECT id",
270→          "FROM feature",
271→          "WHERE id = $feature",
272→          "AND id IN (",
273→          "  SELECT VALUE out",
274→          "  FROM has_feature",
275→          "  WHERE `in` IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
276→          ");",
277→        ].join(" "),
278→        { workspace: workspaceRecord, feature: entityRecord },
279→      )
280→      .collect<[Array<{ id: RecordId<"feature", string> }>]>();
281→
282→    return rows.length > 0;
283→  }
284→
285→  if (table === "task" || table === "decision" || table === "question") {
286→    const [rows] = await surreal
287→      .query<[Array<{ id: RecordId<"task" | "decision" | "question", string> }>]>(
288→        [
289→          "SELECT id",
290→          `FROM ${table}`,
291→          "WHERE id = $entity",
292→          "AND (",
293→          "  id IN (",
294→          "    SELECT VALUE `in`",
295→          "    FROM belongs_to",
296→          "    WHERE out IN (SELECT VALUE out FROM has_project WHERE `in` = $workspace)",
297→          "  )",
298→          "  OR source_message IN (",
