315→export async function listConversationEntities(input: {
316→  surreal: Surreal;
317→  conversationRecord: RecordId<"conversation", string>;
318→  workspaceRecord: RecordId<"workspace", string>;
319→  limit: number;
320→  inheritedEntityIds?: RecordId[];
321→}): Promise<ConversationEntity[]> {
322→  const [rows] = await input.surreal
323→    .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
324→      [
325→        "SELECT `in`, out, confidence, extracted_at",
326→        "FROM extraction_relation",
327→        "WHERE `in` IN (SELECT VALUE id FROM message WHERE conversation = $conversation)",
328→        "ORDER BY extracted_at DESC",
329→        "LIMIT $limit;",
330→      ].join(" "),
331→      {
332→        conversation: input.conversationRecord,
333→        limit: input.limit,
334→      },
335→    )
336→    .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>() ;
337→
338→  const items: ConversationEntity[] = [];
339→  const seen = new Set<string>();
340→
341→  for (const row of rows) {
342→    const table = row.out.table.name as GraphEntityTable;
343→    if (
344→      table !== "workspace" &&
345→      table !== "project" &&
346→      table !== "person" &&
347→      table !== "feature" &&
348→      table !== "task" &&
349→      table !== "decision" &&
350→      table !== "question"
351→    ) {
352→      continue;
353→    }
354→
355→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, row.out);
356→    if (!scoped) {
357→      continue;
358→    }
359→
360→    const entityKey = `${table}:${toRecordIdString(row.out)}`;
361→    if (seen.has(entityKey)) {
362→      continue;
363→    }
364→
365→    const name = await readEntityName(input.surreal, row.out);
366→    if (!name) {
367→      continue;
368→    }
369→
370→    items.push({
371→      id: toRecordIdString(row.out),
372→      kind: table,
373→      name,
374→      confidence: row.confidence,
375→      sourceMessageId: toRecordIdString(row.in),
376→    });
377→    seen.add(entityKey);
378→  }
379→
380→  // Merge inherited entities from parent conversation when branch has sparse context
381→  if (input.inheritedEntityIds && input.inheritedEntityIds.length > 0 && items.length < 5) {
382→    const [inheritedRows] = await input.surreal
383→      .query<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>(
384→        [
385→          "SELECT `in`, out, confidence, extracted_at",
386→          "FROM extraction_relation",
387→          "WHERE out IN $entityIds",
388→          "ORDER BY extracted_at DESC",
389→          "LIMIT $limit;",
390→        ].join(" "),
391→        { entityIds: input.inheritedEntityIds, limit: input.limit },
392→      )
393→      .collect<[Array<{ in: RecordId<"message", string>; out: GraphEntityRecord; confidence: number; extracted_at: string | Date }>]>();
394→
395→    for (const row of inheritedRows) {
396→      const table = row.out.table.name as GraphEntityTable;
397→      if (
398→        table !== "workspace" &&
399→        table !== "project" &&
400→        table !== "person" &&
401→        table !== "feature" &&
402→        table !== "task" &&
403→        table !== "decision" &&
404→        table !== "question"
405→      ) {
406→        continue;
407→      }
408→
409→      const entityKey = `${table}:${toRecordIdString(row.out)}`;
410→      if (seen.has(entityKey)) continue;
411→
412→      const name = await readEntityName(input.surreal, row.out);
413→      if (!name) continue;
414→
415→      items.push({
416→        id: toRecordIdString(row.out),
417→        kind: table,
418→        name,
419→        confidence: row.confidence,
420→        sourceMessageId: toRecordIdString(row.in),
