585→export async function resolveWorkspaceProjectRecord(input: {
586→  surreal: Surreal;
587→  workspaceRecord: RecordId<"workspace", string>;
588→  projectInput: string;
589→}): Promise<RecordId<"project", string>> {
590→  const projectInput = input.projectInput.trim();
591→  if (projectInput.length === 0) {
592→    throw new Error("project identifier is required");
593→  }
594→
595→  if (projectInput.includes(":")) {
596→    const projectRecord = parseRecordIdString(projectInput, ["project"]);
597→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, projectRecord);
598→    if (!scoped) {
599→      throw new Error("project is not linked to this workspace");
600→    }
601→    return projectRecord;
602→  }
603→
604→  const projects = await getWorkspaceProjectRows(input.surreal, input.workspaceRecord);
605→  const normalized = normalizeSearchValue(projectInput);
606→
607→  const exactMatch = projects.find((project) => normalizeSearchValue(project.name) === normalized);
608→  if (exactMatch) {
609→    return exactMatch.id;
610→  }
611→
612→  const fuzzyMatches = projects.filter((project) => normalizeSearchValue(project.name).includes(normalized));
613→  if (fuzzyMatches.length === 1) {
614→    return fuzzyMatches[0].id;
615→  }
616→
617→  if (fuzzyMatches.length > 1) {
618→    throw new Error(`project input is ambiguous: ${fuzzyMatches.map((project) => project.name).join(", ")}`);
619→  }
620→
621→  throw new Error(`project not found in workspace: ${projectInput}`);
622→}
