1341→export async function getDecisionPrimarySourceMessage(input: {
1342→  surreal: Surreal;
1343→  workspaceRecord: RecordId<"workspace", string>;
1344→  decisionRecord: RecordId<"decision", string>;
1345→}): Promise<RecordId<"message", string> | undefined> {
1346→  const decision = await input.surreal.select<{ source_message?: RecordId<"message", string> }>(input.decisionRecord);
