1348→    const workspaceMessageIds = new Set((await getWorkspaceMessageIds(input.surreal, input.workspaceRecord)).map((row) => toRecordIdString(row)));
1349→    if (workspaceMessageIds.has(toRecordIdString(decision.source_message))) {
1350→      return decision.source_message;
1351→    }
1352→  }
1353→
1354→  const [rows] = await input.surreal
1355→    .query<[Array<{ in: RecordId<"message", string> }>]>(
1356→      [
1357→        "SELECT `in`",
1358→        "FROM extraction_relation",
1359→        "WHERE out = $decision",
1360→        "AND `in` IN (",
1361→        "  SELECT VALUE id",
1362→        "  FROM message",
1363→        "  WHERE conversation IN (SELECT VALUE id FROM conversation WHERE workspace = $workspace)",
1364→        ")",
1365→        "ORDER BY extracted_at ASC",
1366→        "LIMIT 1;",
1367→      ].join(" "),
1368→      {
1369→        workspace: input.workspaceRecord,
1370→        decision: input.decisionRecord,
1371→      },
1372→    )
1373→    .collect<[Array<{ in: RecordId<"message", string> }>]>();
1374→
1375→  return rows[0]?.in;
1376→}
