 22→export async function persistExtractionOutput(input: {
 23→  surreal: Surreal;
 24→  embeddingModel: any;
 25→  embeddingDimension: number;
 26→  extractionModelId: string;
 27→  extractionStoreThreshold: number;
 28→  workspaceRecord: RecordId<"workspace", string>;
 29→  sourceRecord: SourceRecord;
 30→  sourceKind: SourceKind;
 31→  sourceLabel?: string;
 32→  promptText: string;
 33→  output: ExtractionPromptOutput;
 34→  sourceMessageRecord?: RecordId<"message", string>;
 35→  sourceChunkRecord?: RecordId<"document_chunk", string>;
 36→  extractionHistoryMessageIds?: string[];
 37→  now: Date;
 38→}): Promise<PersistExtractionResult> {
 39→  const startedAt = performance.now();
 40→  logInfo("extraction.persist.started", "Extraction persistence started", {
 41→    workspaceId: input.workspaceRecord.id as string,
 42→    sourceKind: input.sourceKind,
 43→    sourceId: input.sourceRecord.id as string,
 44→    candidateEntityCount: input.output.entities.length,
 45→    candidateRelationshipCount: input.output.relationships.length,
 46→  });
 47→
 48→  try {
 49→    const entities = postValidateEntities({
 50→      entities: input.output.entities,
 51→      sourceText: input.promptText,
 52→      storeThreshold: input.extractionStoreThreshold,
 53→    });
 54→    if (input.sourceKind === "message" && !input.sourceMessageRecord) {
 55→      throw new Error("message extraction persistence requires sourceMessageRecord");
 56→    }
 57→
 58→    const extractionHistoryMessageIds = new Set(input.extractionHistoryMessageIds ?? []);
 59→    const relationships = postValidateRelationships({
 60→      relationships: input.output.relationships,
 61→      storeThreshold: input.extractionStoreThreshold,
 62→    }).map((relationship) => ({
 63→      ...relationship,
 64→      kind: normalizeRelationshipKind(relationship.kind),
 65→    }));
 66→
 67→    const persistedEntities: ExtractedEntity[] = [];
 68→    const persistedRelationships: ExtractedRelationship[] = [];
 69→    const seeds: OnboardingSeedItem[] = [];
 70→    const embeddingTargets: Array<{ record: GraphEntityRecord; text: string }> = [];
 71→    const entityByTempId = new Map<string, TempEntityReference>();
 72→    const unresolvedAssigneeNames = new Set<string>();
 73→
 74→    const workspaceProjects = await loadWorkspaceProjects(input.surreal, input.workspaceRecord);
 75→
 76→    for (const extracted of entities) {
 77→      const resolvedFromMessageId = resolveValidatedResolvedFromMessageId({
 78→        resolvedFromMessageId: "resolvedFromMessageId" in extracted ? extracted.resolvedFromMessageId : undefined,
 79→        sourceKind: input.sourceKind,
 80→        sourceMessageId: input.sourceMessageRecord?.id as string | undefined,
 81→        extractionHistoryMessageIds,
 82→      });
 83→      const resolvedFromMessageRecord = resolvedFromMessageId
 84→        ? new RecordId("message", resolvedFromMessageId)
 85→        : undefined;
 86→
 87→      const persisted = await upsertGraphEntity({
 88→        surreal: input.surreal,
 89→        embeddingModel: input.embeddingModel,
 90→        embeddingDimension: input.embeddingDimension,
 91→        extractionModelId: input.extractionModelId,
 92→        workspaceRecord: input.workspaceRecord,
 93→        workspaceProjects,
 94→        sourceRecord: input.sourceRecord,
 95→        sourceKind: input.sourceKind,
 96→        promptText: input.promptText,
 97→        extracted: extracted as ExtractionPromptEntity & { kind: Exclude<EntityKind, "workspace" | "person" | "observation"> },
 98→        sourceMessageRecord: input.sourceMessageRecord,
 99→        sourceChunkRecord: input.sourceChunkRecord,
100→        resolvedFromMessageRecord,
101→        now: input.now,
102→      });
103→
104→      entityByTempId.set(extracted.tempId, {
105→        record: persisted.record,
106→        text: persisted.text,
107→        id: persisted.record.id as string,
108→        kind: persisted.kind,
109→      });
110→
111→      const extractedCategory = "category" in extracted ? extracted.category : undefined;
112→
113→      persistedEntities.push({
114→        id: persisted.record.id as string,
115→        kind: persisted.kind,
116→        text: persisted.text,
117→        confidence: extracted.confidence,
118→        sourceKind: input.sourceKind,
119→        sourceId: input.sourceRecord.id as string,
120→        ...(extractedCategory ? { category: extractedCategory } : {}),
121→      });
122→
123→      seeds.push({
124→        id: persisted.record.id as string,
125→        kind: persisted.kind,
126→        text: persisted.text,
127→        confidence: extracted.confidence,
128→        sourceKind: input.sourceKind,
129→        sourceId: input.sourceRecord.id as string,
130→        ...(input.sourceLabel ? { sourceLabel: input.sourceLabel } : {}),
131→        ...(extractedCategory ? { category: extractedCategory } : {}),
132→      });
133→
134→      if (persisted.created) {
135→        embeddingTargets.push({
136→          record: persisted.record,
137→          text: persisted.text,
138→        });
139→      }
140→
141→      const assigneeName = "assignee_name" in extracted ? extracted.assignee_name : undefined;
142→      if (assigneeName) {
143→        const attribution = await applyAssigneeReference({
144→          surreal: input.surreal,
145→          workspaceRecord: input.workspaceRecord,
146→          entityRecord: persisted.record,
147→          entityKind: persisted.kind,
148→          assigneeName,
149→          now: input.now,
150→        });
151→
152→        if (!attribution.resolved) {
153→          unresolvedAssigneeNames.add(attribution.assigneeName);
154→        }
155→      }
156→    }
157→
158→    for (const relationship of relationships) {
159→      const from = entityByTempId.get(relationship.fromTempId);
160→      const to = entityByTempId.get(relationship.toTempId);
161→      if (!from || !to) {
162→        continue;
163→      }
164→
165→      const relationRecord = new RecordId("entity_relation", randomUUID());
166→      await input.surreal.relate(from.record, relationRecord, to.record, {
167→        kind: relationship.kind,
168→        confidence: relationship.confidence,
169→        ...(input.sourceMessageRecord ? { source_message: input.sourceMessageRecord } : {}),
170→        ...(input.sourceChunkRecord ? { source_chunk: input.sourceChunkRecord } : {}),
171→        extracted_at: input.now,
172→        created_at: input.now,
173→        from_text: relationship.fromText,
174→        to_text: relationship.toText,
175→      }).output("after");
176→
177→      persistedRelationships.push({
178→        id: relationRecord.id as string,
179→        kind: relationship.kind,
180→        fromId: from.id,
181→        toId: to.id,
182→        confidence: relationship.confidence,
183→        sourceKind: input.sourceKind,
184→        sourceId: input.sourceRecord.id as string,
185→        ...(input.sourceMessageRecord ? { sourceMessageId: input.sourceMessageRecord.id as string } : {}),
186→        fromText: relationship.fromText,
187→        toText: relationship.toText,
188→      });
189→    }
190→
191→    logInfo("extraction.persist.completed", "Extraction persistence completed", {
192→      workspaceId: input.workspaceRecord.id as string,
193→      sourceKind: input.sourceKind,
194→      sourceId: input.sourceRecord.id as string,
195→      persistedEntityCount: persistedEntities.length,
196→      persistedRelationshipCount: persistedRelationships.length,
197→      seedCount: seeds.length,
198→      toolCount: input.output.tools.length,
199→      unresolvedAssigneeCount: unresolvedAssigneeNames.size,
200→      durationMs: elapsedMs(startedAt),

