475→function cosineSimilarity(a: number[], b: number[]): number {
476→  if (a.length !== b.length) {
477→    return -1;
478→  }
479→
480→  let dot = 0;
481→  let normA = 0;
482→  let normB = 0;
483→
484→  for (let i = 0; i < a.length; i += 1) {
485→    dot += a[i] * b[i];
486→    normA += a[i] * a[i];
487→    normB += b[i] * b[i];
488→  }
489→
490→  if (normA === 0 || normB === 0) {
491→    return -1;
492→  }
493→
494→  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
495→}
