 68→        GET: withRequestLogging(
 69→          "GET /api/workspaces/:workspaceId/conversations/:conversationId",
 70→          "GET",
 71→          (request) =>
 72→            workspaceHandlers.handleWorkspaceConversation(
 73→              request.params.workspaceId,
 74→              request.params.conversationId,
 75→            ),
 76→        ),
 77→      },
 78→      "/api/chat/messages": {
 79→        POST: withRequestLogging("POST /api/chat/messages", "POST", (request) => chatHandlers.handlePostChatMessage(request)),
 80→      },
 81→      "/api/chat/stream/:messageId": {
 82→        GET: withRequestLogging("GET /api/chat/stream/:messageId", "GET", (request) =>
 83→          chatHandlers.handleChatStream(request.params.messageId),
 84→        ),
 85→      },
 86→      "/api/entities/search": {
 87→        GET: withRequestLogging("GET /api/entities/search", "GET", (request) => entitySearchHandler(new URL(request.url))),
 88→      },
 89→      "/api/graph/:workspaceId": {
 90→        GET: withRequestLogging("GET /api/graph/:workspaceId", "GET", (request) =>
 91→          graphHandler(request.params.workspaceId, new URL(request.url)),
 92→        ),
 93→      },
 94→      "/api/entities/:entityId": {
 95→        GET: withRequestLogging("GET /api/entities/:entityId", "GET", (request) =>
 96→          entityDetailHandler(request.params.entityId, new URL(request.url)),
 97→        ),
 98→      },
 99→      "/api/entities/:entityId/actions": {
100→        POST: withRequestLogging("POST /api/entities/:entityId/actions", "POST", (request) =>

  1→import { RecordId } from "surrealdb";
  2→import type { EntityActionRequest } from "../../shared/contracts";
  3→import { HttpError } from "../http/errors";
  4→import { logError, logInfo } from "../http/observability";
  5→import { jsonError, jsonResponse } from "../http/response";
  6→import type { ServerDependencies } from "../runtime/types";
  7→import { resolveWorkspaceRecord } from "../workspace/workspace-scope";
  8→import {
  9→  confirmDecisionRecord,
 10→  isEntityInWorkspace,
 11→  parseRecordIdString,
 12→  type GraphEntityTable,
 13→} from "../graph/queries";
 14→
 15→export function createEntityActionsHandler(
 16→  deps: ServerDependencies,
 17→): (entityId: string, request: Request) => Promise<Response> {
 18→  return (entityId: string, request: Request) => handleEntityAction(deps, entityId, request);
 19→}
 20→
 21→async function handleEntityAction(
 22→  deps: ServerDependencies,
 23→  entityId: string,
 24→  request: Request,
 25→): Promise<Response> {
 26→  let body: EntityActionRequest;
 27→  try {
 28→    body = await request.json() as EntityActionRequest;
 29→  } catch {
 30→    return jsonError("invalid JSON body", 400);
 31→  }
 32→
 33→  if (!body.action || !["confirm", "override", "complete"].includes(body.action)) {
 34→    return jsonError("action must be one of: confirm, override, complete", 400);
 35→  }
 36→
 37→  const url = new URL(request.url);
 38→  const workspaceId = url.searchParams.get("workspaceId")?.trim();
 39→  if (!workspaceId) {
 40→    return jsonError("workspaceId is required", 400);
 41→  }
 42→
 43→  let workspaceRecord;
 44→  try {
 45→    workspaceRecord = await resolveWorkspaceRecord(deps.surreal, workspaceId);
 46→  } catch (error) {
 47→    if (error instanceof HttpError) {
 48→      return jsonError(error.message, error.status);
 49→    }
 50→    logError("entity.action.workspace_resolve.failed", "Failed to resolve workspace", error, { workspaceId });
 51→    return jsonError("failed to resolve workspace", 500);
 52→  }
 53→
 54→  try {
 55→    const entityTables: GraphEntityTable[] = ["workspace", "project", "person", "feature", "task", "decision", "question"];
 56→    const entityRecord = parseRecordIdString(entityId, entityTables);
 57→    const scoped = await isEntityInWorkspace(deps.surreal, workspaceRecord, entityRecord);
 58→    if (!scoped) {
 59→      return jsonError("entity is outside the current workspace scope", 403);
 60→    }
 61→
 62→    const table = entityRecord.table.name;
 63→    const now = new Date();
 64→
 65→    if (body.action === "confirm" && table === "decision") {
 66→      await confirmDecisionRecord({
 67→        surreal: deps.surreal,
 68→        decisionRecord: entityRecord as RecordId<"decision", string>,
 69→        confirmedAt: now,
 70→        notes: body.notes,
 71→      });
 72→      logInfo("entity.action.confirm", "Decision confirmed", { workspaceId, entityId });
 73→      return jsonResponse({ status: "confirmed" }, 200);
 74→    }
 75→
 76→    if (body.action === "override" && table === "decision") {
 77→      if (!body.newSummary) {
 78→        return jsonError("newSummary is required for override action", 400);
 79→      }
 80→      await deps.surreal.update(entityRecord as RecordId<"decision", string>).merge({
 81→        summary: body.newSummary,
 82→        status: "overridden",
 83→        updated_at: now,
 84→        ...(body.notes ? { override_notes: body.notes } : {}),
 85→      });
 86→      logInfo("entity.action.override", "Decision overridden", { workspaceId, entityId });
 87→      return jsonResponse({ status: "overridden" }, 200);
 88→    }
 89→
 90→    if (body.action === "complete" && table === "task") {
 91→      await deps.surreal.update(entityRecord as RecordId<"task", string>).merge({
 92→        status: "done",
 93→        completed_at: now,
 94→        updated_at: now,
 95→      });
 96→      logInfo("entity.action.complete", "Task completed", { workspaceId, entityId });
 97→      return jsonResponse({ status: "completed" }, 200);
 98→    }
 99→
100→    return jsonError(`action '${body.action}' is not valid for entity type '${table}'`, 400);
101→  } catch (error) {
102→    logError("entity.action.failed", "Entity action failed", error, {
103→      workspaceId,
104→      entityId,
105→      action: body.action,
106→    });
107→    const message = error instanceof Error ? error.message : "entity action failed";
108→    return jsonError(message, 500);
109→  }
110→}
111→

