:root {
  font-family: "IBM Plex Sans", "Segoe UI", sans-serif;
  color: #13263f;
  background: radial-gradient(circle at 10% 20%, #d3e8ff 0%, #f4f8fc 45%, #ffffff 100%);

  /* Design token base theme (light) */
  --background: oklch(0.985 0 0);
  --foreground: oklch(0.145 0 0);
  --card: oklch(1.0 0 0);
  --card-foreground: oklch(0.145 0 0);
  --muted: oklch(0.94 0 0);
  --muted-foreground: oklch(0.55 0 0);
  --border: oklch(0.87 0 0);
  --input: oklch(0.87 0 0);
  --ring: oklch(0.145 0 0);
  --destructive: oklch(0.55 0.2 25);

  /* Entity accent palette — OKLCH for perceptual uniformity */
  --entity-project: oklch(0.65 0.15 250);
  --entity-feature: oklch(0.65 0.15 170);
  --entity-task: oklch(0.70 0.15 145);
  --entity-decision: oklch(0.70 0.15 55);
  --entity-question: oklch(0.65 0.15 300);
  --entity-person: oklch(0.65 0.15 25);

  /* Entity foregrounds — high contrast text on accent backgrounds */
  --entity-project-fg: oklch(0.95 0.02 250);
  --entity-feature-fg: oklch(0.95 0.02 170);
  --entity-task-fg: oklch(0.95 0.02 145);
  --entity-decision-fg: oklch(0.95 0.02 55);
  --entity-question-fg: oklch(0.95 0.02 300);
  --entity-person-fg: oklch(0.95 0.02 25);

  /* Entity muted variants — for backgrounds, badges, subtle indicators */
  --entity-project-muted: oklch(0.25 0.05 250);
  --entity-feature-muted: oklch(0.25 0.05 170);
  --entity-task-muted: oklch(0.25 0.05 145);
  --entity-decision-muted: oklch(0.25 0.05 55);
  --entity-question-muted: oklch(0.25 0.05 300);
  --entity-person-muted: oklch(0.25 0.05 25);
}

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  min-height: 100vh;
}

.app-shell {
