  2→import type { SearchEntityResponse } from "../../shared/contracts";
  3→import { HttpError } from "../http/errors";
  4→import { elapsedMs, logDebug, logError, logInfo, logWarn } from "../http/observability";
  5→import { jsonError, jsonResponse } from "../http/response";
  6→import type { ServerDependencies } from "../runtime/types";
  7→import { resolveWorkspaceProjectRecord, resolveWorkspaceRecord } from "../workspace/workspace-scope";
  8→
  9→type SearchEntityRow = {
 10→  id: RecordId<"task" | "decision" | "question", string>;
 11→  kind: "task" | "decision" | "question";
 12→  text: string;
 13→  confidence: number;
 14→  sourceMessage: RecordId<"message", string>;
 15→};
