  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 1rem;
}

.nav-link {
  color: #0057cc;
  text-decoration: none;
  font-weight: 600;
}

.app-main {
  border: 1px solid #bbd2ef;
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.8);
  box-shadow: 0 16px 40px rgba(0, 36, 85, 0.08);
}

