  min-height: 72vh;
  display: flex;
  flex-direction: column;
  padding: 0.75rem;
  gap: 0.75rem;
}

.reachat-header {
  font-size: 0.9rem;
  font-weight: 700;
  color: #194372;
}

.workspace-toolbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 0.6rem;
  border: 1px solid #c8d9ef;
  border-radius: 12px;
  background: #f4f9ff;
  padding: 0.6rem 0.8rem;
}

