  border: 1px solid #9fbfe4;
  border-radius: 10px;
  background: #fff;
  color: #1c4f86;
  padding: 0.42rem 0.7rem;
  font-size: 0.78rem;
  font-weight: 700;
  cursor: pointer;
}

.onboarding-action-buttons button:disabled {
  cursor: not-allowed;
  color: #6f88a6;
  border-color: #c2d4ea;
