.workspace-layout {
  display: grid;
  grid-template-columns: 240px minmax(0, 1fr);
  gap: 0.75rem;
  min-height: 64vh;
}

.chat-main {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  gap: 0.75rem;
  min-height: 0;
}

.chat-main--with-seeds {
  grid-template-columns: minmax(0, 1fr) 280px;
}

/* Conversation sidebar */
.conversation-sidebar {
  border: 1px solid #c7daf2;
  border-radius: 14px;
  background: #fbfdff;
  padding: 0.5rem;
  overflow-y: auto;
  max-height: 72vh;
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
}

