  padding: 0.45rem 0.6rem;
  font-size: 0.78rem;
  font-weight: 700;
  cursor: pointer;
  margin-bottom: 0.25rem;
}

.sidebar-new-conversation:disabled {
  background: #97b4d9;
  cursor: not-allowed;
}

.sidebar-project-group {
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
}

.sidebar-project-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.3rem 0.4rem;
}

.sidebar-project-name {
  font-size: 0.72rem;
  font-weight: 700;
  color: #1f4f80;
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.sidebar-unlinked-label {
  color: #6a7e94;
}

.sidebar-project-count {
  font-size: 0.65rem;
  font-weight: 700;
  color: #4e6784;
  background: #e5f0ff;
  border-radius: 999px;
  padding: 0.1rem 0.38rem;
}

.sidebar-feature-activity {
  display: flex;
  flex-wrap: wrap;
  gap: 0.2rem;
  padding: 0 0.4rem 0.2rem;
}

.sidebar-feature-chip {
  display: inline-flex;
  border-radius: 999px;
  background: #e5f2ff;
  color: #0f4f89;
  font-size: 0.6rem;
  font-weight: 600;
  padding: 0.1rem 0.35rem;
}

.sidebar-conversation-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.1rem;
}

.sidebar-conversation-item {
  width: 100%;
  border: none;
  border-radius: 8px;
  background: transparent;
  padding: 0.35rem 0.5rem;
  font-size: 0.76rem;
  color: #2a4a6b;
  text-align: left;
  cursor: pointer;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.sidebar-conversation-item:hover {
  background: #e8f1fd;
}

.sidebar-conversation-item--active {
  background: #d0e3fc;
  color: #0e3d6e;
  font-weight: 600;
}

.seed-panel {
  border: 1px solid #c7daf2;
  border-radius: 14px;
  background: #fbfdff;
  padding: 0.75rem;
}

.seed-panel h3 {
  margin: 0;
  font-size: 0.92rem;
  color: #1f4f80;
}

.seed-panel p {
  margin: 0.35rem 0 0.7rem;
  font-size: 0.78rem;
  color: #4c6583;
}

.seed-panel ul {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 0.45rem;
  max-height: 56vh;
  overflow: auto;
}

.seed-panel li button {
  width: 100%;
  border: 1px solid #d7e5f7;
  border-radius: 10px;
  background: #fff;
  padding: 0.5rem 0.55rem;
  text-align: left;
  cursor: pointer;
  display: grid;
  gap: 0.18rem;
}

.seed-kind {
  display: inline-flex;
  width: fit-content;
  border-radius: 999px;
  background: #e5f2ff;
  color: #0f4f89;
  font-size: 0.65rem;
  font-weight: 700;
  padding: 0.15rem 0.42rem;
  text-transform: uppercase;
}

.seed-text {
  font-size: 0.79rem;
  color: #213f60;
}

.seed-meta,
.seed-label {
  font-size: 0.7rem;
  color: #4e6784;
}

.source-match-tag {
  margin-top: 0.4rem;
  display: inline-flex;
  border-radius: 999px;
  background: #fff3c8;
  color: #704f00;
  font-size: 0.67rem;
  font-weight: 700;
  padding: 0.2rem 0.5rem;
}

.workspace-setup {
  max-width: 560px;
  margin: 1.5rem auto;
  border: 1px solid #c5d8f0;
  border-radius: 16px;
  background: rgba(255, 255, 255, 0.92);
  padding: 1rem;
}

.workspace-setup h2 {
  margin-top: 0;
  margin-bottom: 0.3rem;
}

.workspace-setup p {
  margin-top: 0;
  font-size: 0.9rem;
  color: #365879;
}

.workspace-form {
  display: grid;
  gap: 0.7rem;
}

.workspace-form label {
  display: grid;
  gap: 0.22rem;
  font-size: 0.82rem;
  font-weight: 600;
  color: #1f4a79;
}

.workspace-form input {
  border: 1px solid #b8d0ee;
  border-radius: 10px;
  padding: 0.55rem 0.65rem;
}

.workspace-form button {
  width: fit-content;
  border: 0;
  border-radius: 10px;
  background: #1f6ad1;
  color: #fff;
  padding: 0.48rem 0.85rem;
  font-weight: 700;
  cursor: pointer;
}

.workspace-form button:disabled {
  background: #97b4d9;
  color: #e8f1ff;
  cursor: not-allowed;
}

/* Reachat's framer-motion message wrappers can remain in hidden state; force visible. */
.reachat-page [style*="translateY(20px)"] {
  opacity: 1 !important;
  transform: none !important;
}

.reachat-page button[title="Upload"] {
  width: 2rem;
  height: 2rem;
  padding: 0;
  border: 1px solid #9ab9dd;
  border-radius: 999px;
  background: #eef5ff;
  color: #1d4e84;
  display: inline-flex;
  align-items: center;
  justify-content: center;
}

.reachat-page button[title="Upload"]:hover {
  background: #dfebfc;
  color: #154378;
}

.reachat-page button[title="Upload"] svg {
  width: 1rem;
  height: 1rem;
  display: block;
}

.error-message {
  margin-top: 0.75rem;
  color: #8a1020;
  font-weight: 600;
}

.extraction-block {
  display: flex;
  flex-direction: column;
  gap: 0.45rem;
  margin-top: 0.55rem;
}

.extraction-row {
  display: flex;
  flex-wrap: wrap;
  gap: 0.45rem;
}

.entity-badge,
.relationship-badge {
  display: inline-flex;
  align-items: center;
  border-radius: 999px;
  font-size: 0.73rem;
  line-height: 1;
  padding: 0.34rem 0.62rem;
  border: 1px solid transparent;
}

.entity-badge {
  background: rgba(15, 114, 71, 0.1);
  color: #0b5e3d;
  border-color: rgba(14, 110, 69, 0.25);
}

.relationship-badge {
  background: rgba(9, 86, 171, 0.1);
  color: #0e4f96;
  border-color: rgba(9, 86, 171, 0.24);
}

.extraction-summary {
  margin-top: 0.7rem;
  border: 1px solid #d6e6fa;
  border-radius: 12px;
  background: #f8fbff;
  padding: 0.65rem;
}

.extraction-summary-title {
  margin: 0 0 0.45rem;
  font-size: 0.78rem;
  font-weight: 700;
  color: #1f527f;
}

.extraction-summary-grid {
  display: grid;
  gap: 0.45rem;
}

.entity-card {
  border: 1px solid #d6e4f6;
  border-radius: 10px;
  background: #fff;
  padding: 0.5rem 0.55rem;
}

.entity-card-header {
  display: flex;
  justify-content: space-between;
  gap: 0.45rem;
}

.entity-kind {
  font-size: 0.67rem;
  font-weight: 700;
  color: #185389;
  text-transform: uppercase;
}

.entity-status {
  font-size: 0.67rem;
  font-weight: 700;
  color: #2f6b2e;
  text-transform: uppercase;
}

.entity-name {
  margin: 0.2rem 0;
  font-size: 0.84rem;
  font-weight: 600;
  color: #1d3f62;
}

.entity-confidence {
  margin: 0;
  font-size: 0.72rem;
  color: #476482;
}

.extraction-summary-meta {
  margin: 0.5rem 0 0;
  font-size: 0.72rem;
  color: #476482;
}

/* --- Work item suggestions --- */

.work-item-suggestion-list {
  margin-top: 0.7rem;
  border: 1px solid #c8daf0;
  border-radius: 12px;
  background: #f5f9ff;
  padding: 0.65rem;
}

.work-item-suggestion-list-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 0.45rem;
}

.work-item-suggestion {
  border: 1px solid #c8daf0;
  border-radius: 10px;
  background: #fff;
  padding: 0.5rem 0.55rem;
  transition: opacity 0.2s;
}

.work-item-suggestion--accepted {
  border-color: #9dd49d;
  background: #f5fbf5;
}

.work-item-suggestion-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 0.45rem;
}

.work-item-actions {
  display: flex;
  gap: 0.3rem;
}

.work-item-btn {
  border: none;
  border-radius: 6px;
  padding: 0.2rem 0.5rem;
  font-size: 0.7rem;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s;
}

.work-item-btn:disabled {
  opacity: 0.5;
  cursor: default;
}

.work-item-btn--accept {
  background: #0057cc;
  color: #fff;
}

.work-item-btn--accept:hover:not(:disabled) {
  background: #004ab3;
}

.work-item-btn--dismiss {
  background: #e8ecf1;
  color: #4a5568;
}

.work-item-btn--dismiss:hover:not(:disabled) {
  background: #d8dce3;
}

.work-item-rationale {
  margin: 0.15rem 0;
  font-size: 0.76rem;
  color: #476482;
}

.work-item-duplicate-hint {
  margin: 0.15rem 0 0;
  font-size: 0.7rem;
  color: #a0522d;
  font-style: italic;
}

.work-item-project {
  margin: 0.15rem 0 0;
  font-size: 0.7rem;
  color: #476482;
}

.work-item-priority {
  font-size: 0.6rem;
  font-weight: 600;
  padding: 0.1rem 0.3rem;
  border-radius: 999px;
  background: #fef3c7;
  color: #92400e;
  text-transform: uppercase;
}

.work-item-accepted-badge {
  font-size: 0.67rem;
  font-weight: 700;
  color: #2f6b2e;
  text-transform: uppercase;
}

@media (max-width: 700px) {
  .app-shell {
    padding: 0.8rem 0.6rem 1.2rem;
  }

  .reachat-page {
    min-height: 78vh;
    padding: 0.35rem;
  }

  .workspace-layout {
    grid-template-columns: 1fr;
  }

  .chat-main--with-seeds {
    grid-template-columns: 1fr;
  }

  .conversation-sidebar {
    max-height: 30vh;
  }

  .seed-panel ul {
    max-height: 28vh;
  }

  .workspace-toolbar {
    flex-direction: column;
    align-items: flex-start;
  }
}

/* --- Graph view --- */

.graph-canvas {
  position: relative;
  width: 100%;
  height: 100%;
  min-height: 64vh;
  background-image: radial-gradient(circle, #c8d9ef 1px, transparent 1px);
  background-size: 20px 20px;
  border-radius: 14px;
  overflow: hidden;
}

.graph-page {
  display: grid;
  grid-template-columns: minmax(0, 1fr);
  grid-template-rows: auto minmax(0, 1fr);
  gap: 0.5rem;
  min-height: 72vh;
  padding: 0.75rem;
}

.graph-page--with-panel {
  grid-template-columns: minmax(0, 1fr) 384px;
}

.graph-page--with-panel .graph-toolbar {
  grid-column: 1 / -1;
}

.graph-toolbar {
  display: flex;
  align-items: center;
  gap: 0.6rem;
  border: 1px solid #c8d9ef;
  border-radius: 12px;
  background: #f4f9ff;
  padding: 0.5rem 0.8rem;
  flex-wrap: wrap;
}

.graph-toolbar select,
.graph-toolbar button {
  border: 1px solid #9fbfe4;
  border-radius: 8px;
  background: #fff;
  color: #1c4f86;
  padding: 0.35rem 0.55rem;
  font-size: 0.78rem;
  font-weight: 600;
  cursor: pointer;
}

.graph-toolbar select:focus,
.graph-toolbar button:focus {
  outline: 2px solid var(--ring, #0057cc);
  outline-offset: 1px;
}

.graph-toolbar label {
  display: flex;
  align-items: center;
  gap: 0.3rem;
  font-size: 0.78rem;
  font-weight: 600;
  color: #1f4a79;
}

.graph-toolbar input[type="range"] {
  width: 80px;
}

.graph-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  color: #4c6583;
  font-size: 0.9rem;
  min-height: 40vh;
}

/* Entity detail panel */

.entity-detail-panel {
  border: 1px solid #c7daf2;
  border-radius: 14px;
  background: #fbfdff;
  padding: 0.75rem;
  overflow-y: auto;
  max-height: 80vh;
  display: flex;
  flex-direction: column;
  gap: 0.6rem;
  animation: slide-in-right 0.2s ease-out;
}

@keyframes slide-in-right {
  from {
    opacity: 0;
    transform: translateX(12px);
  }
  to {
    opacity: 1;
    transform: translateX(0);
  }
}

.entity-detail-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 0.5rem;
}

.entity-detail-header h3 {
  margin: 0;
  font-size: 0.95rem;
  color: #1d3f62;
}

.entity-detail-close {
  border: none;
  background: transparent;
  color: #4e6784;
  font-size: 1.1rem;
  cursor: pointer;
  padding: 0.1rem 0.3rem;
  line-height: 1;
}

.entity-detail-section {
  display: flex;
  flex-direction: column;
  gap: 0.25rem;
}

.entity-detail-section h4 {
  margin: 0;
  font-size: 0.72rem;
  font-weight: 700;
  color: #1f4f80;
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.entity-detail-meta {
  font-size: 0.78rem;
  color: #4c6583;
}

.entity-detail-meta dt {
  font-weight: 600;
  color: #2a4a6b;
  display: inline;
}

.entity-detail-meta dt::after {
  content: ": ";
}

.entity-detail-meta dd {
  display: inline;
  margin: 0;
}

.entity-detail-meta dd::after {
  content: "";
  display: block;
  margin-bottom: 0.15rem;
}

.entity-detail-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.4rem;
  padding-top: 0.3rem;
}

.entity-detail-actions button {
  border: 1px solid #9fbfe4;
  border-radius: 8px;
  background: #fff;
  color: #1c4f86;
  padding: 0.35rem 0.6rem;
  font-size: 0.78rem;
  font-weight: 600;
  cursor: pointer;
}

.entity-detail-actions button:hover {
  background: #e8f1fd;
}

.entity-detail-actions button:disabled {
  cursor: not-allowed;
  color: #6f88a6;
  border-color: #c2d4ea;
}

/* Description section */

.entity-detail-description {
  font-size: 0.82rem;
  color: #2a4a6b;
  line-height: 1.5;
  margin: 0;
}

.description-timeline-toggle {
  border: none;
  background: transparent;
  font-size: 0.7rem;
  color: #6f88a6;
  cursor: pointer;
  padding: 0.2rem 0;
  text-align: left;
}

.description-timeline-toggle:hover {
  color: #2a4a6b;
}

.description-timeline {
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  border-left: 2px solid #c7daf2;
  padding-left: 0.75rem;
  margin-top: 0.25rem;
}

.description-timeline-entry {
  display: flex;
  flex-direction: column;
  gap: 0.1rem;
}

.description-timeline-date {
  font-size: 0.65rem;
  color: #8ba0b8;
  font-weight: 600;
}

.description-timeline-text {
  font-size: 0.76rem;
  color: #2a4a6b;
}

.description-timeline-reasoning {
  font-size: 0.65rem;
  color: #8ba0b8;
  font-style: italic;
}

/* Entity badge (inline kind indicator) */

.entity-badge-inline {
  display: inline-flex;
  align-items: center;
  gap: 0.25rem;
  border-radius: 999px;
  font-size: 0.67rem;
  font-weight: 700;
  padding: 0.15rem 0.42rem;
  text-transform: uppercase;
}

.category-badge {
  display: inline-flex;
  align-items: center;
  gap: 0.25rem;
  border-radius: 999px;
  font-size: 0.6rem;
  font-weight: 600;
  padding: 0.12rem 0.38rem;
  background: var(--muted);
  color: var(--muted-foreground);
  text-transform: capitalize;
}

/* Relationship list in detail panel */

.relationship-group {
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
}

.relationship-group-label {
  font-size: 0.67rem;
  font-weight: 700;
  color: #4e6784;
  text-transform: uppercase;
  letter-spacing: 0.03em;
}

.relationship-item {
  display: flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.25rem 0.35rem;
  border-radius: 6px;
  cursor: pointer;
  font-size: 0.78rem;
  color: #2a4a6b;
}

.relationship-item:hover {
  background: #e8f1fd;
}

/* Provenance section */

.provenance-item {
  border: 1px solid #e2ecf7;
  border-radius: 8px;
  padding: 0.4rem 0.5rem;
  font-size: 0.76rem;
  color: #365879;
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
}

.provenance-evidence {
  font-style: italic;
  color: #4c6583;
}

.provenance-link {
  color: #0057cc;
  text-decoration: none;
  font-weight: 600;
  font-size: 0.72rem;
  cursor: pointer;
}

.provenance-link:hover {
  text-decoration: underline;
}

/* View tabs */

.view-tabs {
  display: flex;
  gap: 0.2rem;
}

.view-tab {
  color: #0057cc;
  text-decoration: none;
  font-weight: 600;
  padding: 0.25rem 0.5rem;
  border-radius: 6px;
}

.view-tab:hover {
  background: #e8f1fd;
}

.view-tab--active {
  background: #d0e3fc;
  color: #0e3d6e;
}

/* Graph icon on entity card */

.entity-card-graph-link {
  border: none;
  background: transparent;
  color: #0057cc;
  cursor: pointer;
  padding: 0.15rem;
  line-height: 1;
  font-size: 0.8rem;
  border-radius: 4px;
}

.entity-card-graph-link:hover {
  background: #e8f1fd;
}

/* Message highlight animation (graph → chat navigation) */

@keyframes highlight-message {
  0% {
    background: rgba(0, 87, 204, 0.15);
  }
  100% {
    background: transparent;
  }
}

.animate-highlight {
  animation: highlight-message 2s ease-out;
}

/* Branch: inherited messages */
.message-inherited {
  opacity: 0.55;
  border-left: 2px solid var(--border, #d0d0d0);
  padding-left: 8px;
}

.branch-divider {
  text-align: center;
  font-size: 0.75rem;
  color: var(--muted-foreground, #888);
  padding: 8px 0;
  border-bottom: 1px dashed var(--border, #d0d0d0);
  margin-bottom: 8px;
}

.branch-message-btn {
  display: flex;
  align-items: center;
  justify-content: center;
  margin: 2px 0 8px auto;
  padding: 4px;
  color: var(--muted-foreground, #888);
  background: transparent;
  border: 1px solid transparent;
  border-radius: 6px;
  cursor: pointer;
  opacity: 0;
  transition: opacity 0.15s, background 0.15s, border-color 0.15s;
}

[data-message-id]:hover .branch-message-btn {
  opacity: 0.5;
}

.branch-message-btn:hover {
  opacity: 1 !important;
  background: var(--accent, #f0f0f0);
  border-color: var(--border, #d0d0d0);
}

.branch-message-btn:disabled {
  cursor: not-allowed;
  opacity: 0.2 !important;
}

