  1→import { afterAll, beforeAll, describe, expect, it } from "bun:test";
  2→import { randomUUID } from "node:crypto";
  3→import { readFileSync } from "node:fs";
  4→import { join } from "node:path";
  5→import { RecordId, Surreal } from "surrealdb";
  6→import { loadBranchChain, loadMessagesWithInheritance } from "../../app/src/server/chat/branch-chain";
  7→
  8→const surrealUrl = process.env.SURREAL_URL ?? "ws://127.0.0.1:8000/rpc";
  9→const surrealUsername = process.env.SURREAL_USERNAME ?? "root";
 10→const surrealPassword = process.env.SURREAL_PASSWORD ?? "root";
 11→
 12→let surreal: Surreal;
 13→let namespace: string;
 14→let database: string;
 15→
 16→beforeAll(async () => {
 17→  const runId = `${Date.now()}_${Math.floor(Math.random() * 100000)}`;
 18→  namespace = `branch_test_${runId}`;
 19→  database = `branch_${Math.floor(Math.random() * 100000)}`;
 20→
 21→  surreal = new Surreal();
 22→  await surreal.connect(surrealUrl);
 23→  await surreal.signin({ username: surrealUsername, password: surrealPassword });
 24→  await surreal.query(`DEFINE NAMESPACE ${namespace};`);
 25→  await surreal.use({ namespace });
 26→  await surreal.query(`DEFINE DATABASE ${database};`);
 27→  await surreal.use({ namespace, database });
 28→
 29→  const schema = readFileSync(join(process.cwd(), "schema", "surreal-schema.surql"), "utf8");
 30→  await surreal.query(schema);
 31→}, 30_000);
 32→
 33→afterAll(async () => {
 34→  try { await surreal.query(`REMOVE DATABASE ${database};`); } catch {}
 35→  try { await surreal.query(`REMOVE NAMESPACE ${namespace};`); } catch {}
 36→  await surreal.close().catch(() => {});
 37→}, 10_000);
 38→
 39→// ── Helpers ──
 40→
 41→function ts(base: number, offsetMs: number): Date {
 42→  return new Date(base + offsetMs);
 43→}
 44→
 45→async function createConversation(): Promise<string> {
 46→  const id = randomUUID();
 47→  const now = new Date();
 48→  await surreal.query("CREATE $record CONTENT $content;", {
 49→    record: new RecordId("conversation", id),
 50→    content: {
 51→      createdAt: now,
 52→      updatedAt: now,
 53→      workspace: new RecordId("workspace", "test-ws"),
 54→      title: "test",
 55→      title_source: "message",
 56→    },
 57→  });
 58→  return id;
 59→}
 60→
 61→async function insertMsg(
 62→  conversationId: string,
 63→  role: "user" | "assistant",
 64→  text: string,
 65→  createdAt: Date,
 66→): Promise<string> {
 67→  const id = randomUUID();
 68→  await surreal.query("CREATE $record CONTENT $content;", {
 69→    record: new RecordId("message", id),
 70→    content: {
 71→      conversation: new RecordId("conversation", conversationId),
 72→      role,
 73→      text,
 74→      createdAt,
 75→    },
 76→  });
 77→  return id;
 78→}
 79→
 80→async function relateBranch(
 81→  childConvId: string,
 82→  parentConvId: string,
 83→  branchPointMsgId: string,
 84→): Promise<void> {
 85→  await surreal.query(
 86→    "RELATE $child->branched_from->$parent SET branched_at = time::now(), branch_point_message = $msg;",
 87→    {
 88→      child: new RecordId("conversation", childConvId),
 89→      parent: new RecordId("conversation", parentConvId),
 90→      msg: new RecordId("message", branchPointMsgId),
 91→    },
 92→  );
 93→}
 94→
 95→// ── Tests ──
 96→
 97→describe("branch inheritance", () => {
 98→  it("branch includes inherited messages up to branch point + assistant response", async () => {
 99→    const rootId = await createConversation();
100→    const base = Date.now();
101→
102→    // Root: user1, assistant1, user2, assistant2, user3
103→    await insertMsg(rootId, "user", "Root user 1", ts(base, 1000));
104→    await insertMsg(rootId, "assistant", "Root assistant 1", ts(base, 2000));
105→    const branchPointId = await insertMsg(rootId, "user", "Root user 2", ts(base, 3000));
106→    await insertMsg(rootId, "assistant", "Root assistant 2", ts(base, 4000));
107→    await insertMsg(rootId, "user", "Root user 3 (after branch)", ts(base, 5000));
108→
109→    // Branch from user2 — should inherit user1, assistant1, user2, assistant2
110→    const branchId = await createConversation();
111→    await relateBranch(branchId, rootId, branchPointId);
112→
113→    await insertMsg(branchId, "user", "Branch user 1", ts(base, 10000));
114→    await insertMsg(branchId, "assistant", "Branch assistant 1", ts(base, 11000));
115→
116→    // Verify chain
117→    const chain = await loadBranchChain(surreal, branchId);
118→    expect(chain).toHaveLength(1);
119→    expect(chain[0].parentConversationId).toBe(rootId);
120→    expect(chain[0].conversationId).toBe(branchId);
121→    expect(chain[0].branchPointMessageId).toBe(branchPointId);
122→
123→    // Verify inherited messages
124→    const messages = await loadMessagesWithInheritance(surreal, branchId, 50);
125→    const inherited = messages.filter((m) => m.inherited);
126→    const own = messages.filter((m) => !m.inherited);
127→
128→    const inheritedTexts = inherited.map((m) => m.text);
129→    expect(inheritedTexts).toContain("Root user 1");
130→    expect(inheritedTexts).toContain("Root assistant 1");
131→    expect(inheritedTexts).toContain("Root user 2");
132→    expect(inheritedTexts).toContain("Root assistant 2");
133→    expect(inheritedTexts).not.toContain("Root user 3 (after branch)");
134→    expect(inherited).toHaveLength(4);
135→
136→    const ownTexts = own.map((m) => m.text);
137→    expect(ownTexts).toEqual(["Branch user 1", "Branch assistant 1"]);
138→
139→    // Chronological order
140→    for (let i = 1; i < messages.length; i++) {
141→      const prev = new Date(messages[i - 1].createdAt).getTime();
142→      const curr = new Date(messages[i].createdAt).getTime();
143→      expect(curr).toBeGreaterThanOrEqual(prev);
144→    }
145→  });
146→
147→  it("multi-level branching (root → A → B) inherits from all ancestors", async () => {
148→    const rootId = await createConversation();
149→    const base = Date.now();
150→
151→    // Root: 2 pairs
152→    const rootMsg1 = await insertMsg(rootId, "user", "Root msg 1", ts(base, 1000));
153→    await insertMsg(rootId, "assistant", "Root reply 1", ts(base, 2000));
154→    await insertMsg(rootId, "user", "Root msg 2", ts(base, 3000));
155→    await insertMsg(rootId, "assistant", "Root reply 2", ts(base, 4000));
156→
157→    // Branch A from rootMsg1
158→    const branchAId = await createConversation();
159→    await relateBranch(branchAId, rootId, rootMsg1);
160→
161→    const branchAMsg1 = await insertMsg(branchAId, "user", "A msg 1", ts(base, 10000));
162→    await insertMsg(branchAId, "assistant", "A reply 1", ts(base, 11000));
163→    await insertMsg(branchAId, "user", "A msg 2", ts(base, 12000));
164→    await insertMsg(branchAId, "assistant", "A reply 2", ts(base, 13000));
165→
166→    // Branch B from branchAMsg1
167→    const branchBId = await createConversation();
168→    await relateBranch(branchBId, branchAId, branchAMsg1);
